\begin{lemma}[The quotient module \(M/xM\)]
  \label{lem:quotSMulTop_mathlib}
  \lean{QuotSMulTop}
  \mathlibok
  \textit{Provided by Mathlib (\texttt{Mathlib.RingTheory.QuotSMulTop}).}
  For a commutative ring \(R\), an element \(x \in R\) and an \(R\)-module \(M\),
  Mathlib provides the cokernel of multiplication by \(x\) on \(M\),
  \[
    M/xM,
  \]
  as a named construction. It is the object \(C = M/xM\) whose induced grading is
  supplied by \cref{lem:graded_quotient_decomposition}.
\end{lemma}

